    42	int16_t get_prach_tx_power(NR_UE_MAC_INST_t *mac)
    43	{
    44	  RA_config_t *ra = &mac->ra;
    45	  int16_t pathloss = compute_nr_SSB_PL(mac, mac->ssb_measurements.ssb_rsrp_dBm);
    46	  int16_t ra_preamble_rx_power = (int16_t)(ra->prach_resources.ra_preamble_rx_target_power + pathloss);
    47	  return min(ra->prach_resources.Pc_max, ra_preamble_rx_power);
    48	}
