    91	static int get_Msg3SizeGroupA(long ra_Msg3SizeGroupA)
    92	{
    93	  int bits = 0;
    94	  switch (ra_Msg3SizeGroupA) {
    95	    case NR_RACH_ConfigCommon__groupBconfigured__ra_Msg3SizeGroupA_b56:
    96	      bits = 56;
    97	      break;
    98	    case NR_RACH_ConfigCommon__groupBconfigured__ra_Msg3SizeGroupA_b144:
    99	      bits = 144;
   100	      break;
   101	    case NR_RACH_ConfigCommon__groupBconfigured__ra_Msg3SizeGroupA_b208:
   102	      bits = 208;
   103	      break;
   104	    case NR_RACH_ConfigCommon__groupBconfigured__ra_Msg3SizeGroupA_b256:
   105	      bits = 256;
   106	      br
... [truncated] ...
d__ra_Msg3SizeGroupA_b72:
   123	      bits = 72;
   124	      break;
   125	    default:
   126	      AssertFatal(false, "Unknown ra-Msg3SizeGroupA %lu\n", ra_Msg3SizeGroupA);
   127	  }
   128	  return bits / 8; // returning bytes
