   131	static int get_messagePowerOffsetGroupB(long messagePowerOffsetGroupB)
   132	{
   133	  int pow_offset = 0;
   134	  switch (messagePowerOffsetGroupB) {
   135	    case NR_RACH_ConfigCommon__groupBconfigured__messagePowerOffsetGroupB_minusinfinity:
   136	      pow_offset = INT_MIN;
   137	      break;
   138	    case NR_RACH_ConfigCommon__groupBconfigured__messagePowerOffsetGroupB_dB0:
   139	      pow_offset = 0;
   140	      break;
   141	    case NR_RACH_ConfigCommon__groupBconfigured__messagePowerOffsetGroupB_dB5:
   142	      pow_offset = 5;
   143	      break;
   144	    case NR_RACH_ConfigCommon__groupBconfigured__messagePowerOffsetGroupB_dB8:
   145	      pow_offset = 8;
   146	      break;
   147	    case NR_RACH_ConfigCommon__groupBconfigured__messagePowerOffsetGroupB_dB10:
   148	      pow_offset = 10;
   149	      break;
   150	    case NR_RACH_ConfigCommon__groupBconfigured__messagePowerOffsetGroupB_dB12:
   151	      pow_offset = 12;
   152	      break;
   153	    case NR_RACH_ConfigCommon__groupBconfigured__messagePowerOffsetGroupB_dB15:
   154	      pow_offset = 15;
   155	      break;
   156	    case NR_RACH_ConfigCommon__groupBconfigured__messagePowerOffsetGroupB_dB18:
   157	      pow_offset = 18;
   158	      break;
   159	    default:
   160	      AssertFatal(false, "Unknown messagePowerOffsetGroupB %lu\n", messagePowerOffsetGroupB);
   161	  }
   162	  return pow_offset;
   163	}
