   165	static void select_preamble_group(NR_UE_MAC_INST_t *mac)
   166	{
   167	  RA_config_t *ra = &mac->ra;
   168	  // TODO if the RA_TYPE is switched from 2-stepRA to 4-stepRA
   169	
   170	  if (!ra->Msg3_buffer) { // if Msg3 buffer is empty
   171	    NR_RACH_ConfigCommon_t *nr_rach_ConfigCommon = mac->current_UL_BWP->rach_ConfigCommon;
   172	    if (nr_rach_ConfigCommon && nr_rach_ConfigCommon->groupBconfigured) { // if Random Access Preambles group B is configured
   173	      struct NR_RACH_ConfigCommon__groupBconfigured *groupB = nr_rach_ConfigCommon->groupBconfigured;
   174	      // if the potential Msg3 size (UL data available for transmission plus MAC subheader(s) and,
   175	      // where required, MAC CEs) is greater than ra-Msg3SizeGroupA
   176	      // if the pathloss is less than PCMAX (of the Serving Cell performing the Random Access Procedure)
   177	      // – preambleReceivedTargetPower – msg3-DeltaPreamble – messagePowerOffsetGroupB
   178	      int groupB_pow_offset = get_messagePowerOffsetGroupB(groupB->messagePowerOffsetGroupB);
   179	      int PLThreshold = ra->prach_resources.Pc_max - ra->preambleRxTargetPower - ra->msg3_deltaPreamble - groupB_pow_offset;
   180	      int pathloss = compute_nr_SSB_PL(mac, mac->ssb_measurements.ssb_rsrp_dBm);
   181	      // TODO if the Random Access procedure was initiated for the CCCH logical channel and the CCCH SDU size
   182	      // plus MAC subheader is greater than ra-Msg3SizeGroupA
   183	      if (ra->Msg3_size > get_Msg3SizeGroupA(groupB->ra_Msg3SizeGroupA) && pathloss < PLThreshold)
   184	        ra->RA_GroupA = false;
   185	      else
   186	        ra->RA_GroupA = true;
   187	    } else
   188	      ra->RA_GroupA = true;
   189	  }
   190	  // else if Msg3 is being retransmitted, we keep what used in first transmission of Msg3
   191	}
