    36	static f1ap_net_config_t read_DU_IP_config(const eth_params_t* f1_params, const char *f1u_ip_addr)
    37	{
    38	  f1ap_net_config_t nc = {0};
    39	
    40	  nc.CU_f1_ip_address= strdup(f1_params->remote_addr);
    41	  nc.CUport = f1_params->remote_portd;
    42	
    43	  nc.DU_f1c_ip_address = strdup(f1_params->my_addr);
    44	  nc.DU_f1u_ip_address = strdup(f1u_ip_addr);
    45	  nc.DUport = f1_params->my_portd;
    46	  LOG_I(F1AP,
    47	        "F1-C DU IPaddr %s, connect to F1-C CU %s, binding GTP to %s\n",
    48	        nc.DU_f1c_ip_address,
    49	        nc.CU_f1_ip_address,
    50	        nc.DU_f1u_ip_address);
    51	
    52	  // sctp_in_streams/sctp_out_streams are given by SCTP layer
    53	  return nc;
    54	}
