    78	static void gnb_du_configuration_update_f1ap(const f1ap_gnb_du_configuration_update_t *upd)
    79	{
    80	  MessageDef *msg = itti_alloc_new_message(TASK_MAC_GNB, 0, F1AP_GNB_DU_CONFIGURATION_UPDATE);
    81	  /* copy F1AP message */
    82	  f1ap_gnb_du_configuration_update_t cp = cp_f1ap_du_configuration_update(upd);
