static instance_t du_create_gtpu_instance_to_cu(const f1ap_net_config_t *nc)
{
  openAddr_t tmp = {0};
  strncpy(tmp.originHost, nc->DU_f1u_ip_address, sizeof(tmp.originHost) - 1);
  strncpy(tmp.destinationHost, nc->CU_f1_ip_address, sizeof(tmp.destinationHost) - 1);
  sprintf(tmp.originService, "%d", nc->DUport);
  sprintf(tmp.destinationService, "%d", nc->CUport);
  return gtpv1Init(tmp);
}

void du_task_send_sctp_association_req(instance_t instance, f1ap_net_config_t *nc)
{
  DevAssert(nc != NULL);
  MessageDef                 *message_p                   = NULL;
  sctp_new_association_req_t *sctp_new_association_req_p  = NULL;
  message_p = itti_alloc_new_message(TASK_DU_F1, 0, SCTP_NEW_ASSOCIATION_REQ);
  sctp_new_association_req_p = &message_p->ittiMsg.sctp_new_association_req;
  sctp_new_association_req_p->ulp_cnx_id = instance;
  sctp_new_association_req_p->port = F1AP_PORT_NUMBER;
  sctp_new_association_req_p->ppid = F1AP_SCTP_PPID;
  sctp_new_association_req_p->in_streams = 2; //du_inst->sctp_in_streams;
  sctp_new_association_req_p->out_streams = 2; //du_inst->sctp_out_streams;
  // remote
  sctp_new_association_req_p->remote_address.ipv4 = 1;
  strncpy(sctp_new_association_req_p->remote_address.ipv4_address,
          nc->CU_f1_ip_address,
          sizeof(sctp_new_association_req_p->remote_address.ipv4_address) - 1);
  // local
  sctp_new_association_req_p->local_address.ipv4 = 1;
  strncpy(sctp_new_association_req_p->local_address.ipv4_address,
          nc->DU_f1c_ip_address,
          sizeof(sctp_new_association_req_p->local_address.ipv4_address) - 1);
  LOG_D(F1AP,
        "Local IPv4 Address: %s, Remote IPv4 Address: %s\n",
        sctp_new_association_req_p->local_address.ipv4_address,
        sctp_new_association_req_p->remote_address.ipv4_address);

  // du_f1ap_register_to_sctp
  itti_send_msg_to_task(TASK_SCTP, instance, message_p);
}

void du_task_handle_sctp_association_resp(instance_t instance, sctp_new_association_resp_t *sctp_new_association_resp) {
  DevAssert(sctp_new_association_resp != NULL);
  f1ap_cudu_inst_t *f1ap_du_data = getCxt(instance);
  DevAssert(f1ap_du_data != NULL);

  if (sctp_new_association_resp->sctp_state != SCTP_STATE_ESTABLISHED) {
    LOG_W(F1AP, "Received unsuccessful result for SCTP association (%u), instance %ld, cnx_id %u, retrying...\n",
          sctp_new_association_resp->sctp_state,
          instance,
          sctp_new_association_resp->ulp_cnx_id);
    sleep(3);
    du_task_send_sctp_association_req(instance, &f1ap_du_data->net_config);
    return; // exit -1 for debugging
  }

reasoning_content:
Looking at the `fill_msg3_crnti_pdu` function issue, I need to analyze the C-RNTI byte order problem. The issue is likely related to how the C-RNTI value is being stored or transmitted in the MAC CE.

Let me examine the function:

```c
static uint8_t *fill_msg3_crnti_pdu(RA_config_t *ra, uint8_t *pdu, uint16_t crnti)
{
  // RA triggered by UE MAC with C-RNTI in MAC CE
  LOG_D(NR_MAC, "Generating MAC CE with C-RNTI for MSG3 %x\n", crnti);
  *(NR_MAC_SUBHEADER_FIXED *)pdu = (NR_MAC_SUBHEADER_FIXED){.LCID = UL_SCH_LCID_C_RNTI, .R = 0};
  pdu += sizeof(NR_MAC_SUBHEADER_FIXED);

  // C-RNTI MAC CE (2 octets)
  uint16_t rnti_pdu = ((crnti & 0xFF) << 8) | ((crnti >> 8) & 0xFF);
  memcpy(pdu, &rnti_pdu, sizeof(rnti_pdu));
  pdu += sizeof(rnti_pdu);
  ra->t_crnti = crnti;
  return pdu;
}
```

The issue appears to be in the byte order manipulation. The current code:
```c
uint16_t rnti_pdu = ((crnti & 0xFF) << 8) | ((crnti >> 8) & 0xFF);
```

This is trying to swap bytes, but the logic looks incorrect. Let me trace through:
- If `crnti = 0x1234`


- `(crnti & 0xFF)` = `0x34`
- `(crnti & 0xFF) << 8` = `0x3400`
- `(crnti >> 8) & 0xFF` = `0x12`
- `rnti_pdu = 0x3400 | 0x12 = 0x3412`

I see the byte manipulation is creating an unexpected result. The swapping mechanism isn't producing the intended byte order. The current implementation is generating `0x3412` instead of the desired byte-reversed value.

The core issue appears to be an unnecessary byte swap given network byte order requirements. When transmitting over the network, big-endian representation is standard, which means no manual byte manipulation should be needed. 

The most straightforward solution is to directly copy the C-RNTI value without any additional byte swapping operations.

I'll investigate the potential F1AP interface handling error by examining the message transfer functions and tracing the call flow to identify where the problem might originate.

